module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);

    reg [63:0] adda_reg;
    reg [63:0] addb_reg;
    reg i_en_reg;

    wire [64:0] sum;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'b0;
            addb_reg <= 64'b0;
            i_en_reg <= 1'b0;
            o_en <= 1'b0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            i_en_reg <= i_en;
            o_en <= i_en_reg;
        end
    end

    assign sum = adda_reg + addb_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            result <= 65'b0;
        end else begin
            result <= {sum[64], sum};
        end
    end

endmodule
